You are implementing a veterinary clinic management Blazor Web App. The project is already scaffolded at `/tmp/sv-c13dd1ffc9354ee398a3808be4c0330d/VetClinic/`.

It uses:
- .NET 11 preview (net11.0)
- Interactive Server mode, global (all pages interactive by default)
- ASP.NET Core Identity with Individual accounts (SQLite)
- EF Core with SQLite

## What to implement

### 1. Domain Models

Create `/tmp/sv-c13dd1ffc9354ee398a3808be4c0330d/VetClinic/Data/Models.cs` with these entities:

```csharp
namespace VetClinic.Data;

public class Owner
{
    public int Id { get; set; }
    public string FirstName { get; set; } = "";
    public string LastName { get; set; } = "";
    public string Phone { get; set; } = "";
    public string Email { get; set; } = "";
    public List<Pet> Pets { get; set; } = new();
}

public class Pet
{
    public int Id { get; set; }
    public string Name { get; set; } = "";
    public string Species { get; set; } = ""; // Dog, Cat, Bird, etc.
    public string Breed { get; set; } = "";
    public DateTime DateOfBirth { get; set; }
    public double Weight { get; set; }
    public int OwnerId { get; set; }
    public Owner Owner { get; set; } = null!;
    public List<Treatment> Treatments { get; set; } = new();
    public List<Appointment> Appointments { get; set; } = new();
}

public class Treatment
{
    public int Id { get; set; }
    public int PetId { get; set; }
    public Pet Pet { get; set; } = null!;
    public DateTime Date { get; set; }
    public string Description { get; set; } = "";
    public string Notes { get; set; } = "";
    public string Veterinarian { get; set; } = "";
}

public class Appointment
{
    public int Id { get; set; }
    public int PetId { get; set; }
    public Pet Pet { get; set; } = null!;
    public DateTime StartTime { get; set; }
    public DateTime EndTime { get; set; }
    public string Reason { get; set; } = "";
    public AppointmentStatus Status { get; set; } = AppointmentStatus.Scheduled;
    public string Veterinarian { get; set; } = "";
}

public enum AppointmentStatus
{
    Scheduled,
    Completed,
    Cancelled
}

public class Invoice
{
    public int Id { get; set; }
    public int PetId { get; set; }
    public Pet Pet { get; set; } = null!;
    public DateTime Date { get; set; }
    public decimal Total { get; set; }
    public bool IsPaid { get; set; }
    public string Description { get; set; } = "";
    public List<InvoiceLineItem> LineItems { get; set; } = new();
    public List<Payment> Payments { get; set; } = new();
}

public class InvoiceLineItem
{
    public int Id { get; set; }
    public int InvoiceId { get; set; }
    public Invoice Invoice { get; set; } = null!;
    public string Description { get; set; } = "";
    public decimal Amount { get; set; }
    public int Quantity { get; set; } = 1;
}

public class Payment
{
    public int Id { get; set; }
    public int InvoiceId { get; set; }
    public Invoice Invoice { get; set; } = null!;
    public DateTime Date { get; set; }
    public decimal Amount { get; set; }
    public string Method { get; set; } = ""; // Cash, Card, Check
}
```

### 2. Update ApplicationDbContext

Edit `/tmp/sv-c13dd1ffc9354ee398a3808be4c0330d/VetClinic/Data/ApplicationDbContext.cs` to add DbSets:

```csharp
using Microsoft.AspNetCore.Identity.EntityFrameworkCore;
using Microsoft.EntityFrameworkCore;

namespace VetClinic.Data;

public class ApplicationDbContext(DbContextOptions<ApplicationDbContext> options) : IdentityDbContext<ApplicationUser>(options)
{
    public DbSet<Owner> Owners => Set<Owner>();
    public DbSet<Pet> Pets => Set<Pet>();
    public DbSet<Treatment> Treatments => Set<Treatment>();
    public DbSet<Appointment> Appointments => Set<Appointment>();
    public DbSet<Invoice> Invoices => Set<Invoice>();
    public DbSet<InvoiceLineItem> InvoiceLineItems => Set<InvoiceLineItem>();
    public DbSet<Payment> Payments => Set<Payment>();

    protected override void OnModelCreating(ModelBuilder builder)
    {
        base.OnModelCreating(builder);

        builder.Entity<Invoice>()
            .Property(i => i.Total)
            .HasColumnType("decimal(18,2)");

        builder.Entity<InvoiceLineItem>()
            .Property(i => i.Amount)
            .HasColumnType("decimal(18,2)");

        builder.Entity<Payment>()
            .Property(p => p.Amount)
            .HasColumnType("decimal(18,2)");
    }
}
```

