### 5. Update Home.razor (Dashboard)

Replace `/tmp/sv-c13dd1ffc9354ee398a3808be4c0330d/VetClinic/Components/Pages/Home.razor` with:

```razor
@page "/"
@using Microsoft.AspNetCore.Authorization
@using Microsoft.EntityFrameworkCore
@using VetClinic.Data
@attribute [Authorize]
@inject ApplicationDbContext Db

<PageTitle>Dashboard - VetClinic</PageTitle>

<h1>Clinic Dashboard</h1>

<div class="row mt-4">
    <div class="col-md-3">
        <div class="card text-bg-primary mb-3">
            <div class="card-body">
                <h5 class="card-title">Patients</h5>
                <p class="card-text display-6">@petCount</p>
            </div>
        </div>
    </div>
    <div class="col-md-3">
        <div class="card text-bg-success mb-3">
            <div class="card-body">
                <h5 class="card-title">Today's Appointments</h5>
                <p class="card-text display-6">@todayAppointments</p>
            </div>
        </div>
    </div>
    <div class="col-md-3">
        <div class="card text-bg-warning mb-3">
            <div class="card-body">
                <h5 class="card-title">Unpaid Invoices</h5>
                <p class="card-text display-6">@unpaidInvoices</p>
            </div>
        </div>
    </div>
    <div class="col-md-3">
        <div class="card text-bg-info mb-3">
            <div class="card-body">
                <h5 class="card-title">Owners</h5>
                <p class="card-text display-6">@ownerCount</p>
            </div>
        </div>
    </div>
</div>

<div class="row mt-4">
    <div class="col-md-6">
        <h4>Upcoming Appointments</h4>
        @if (upcomingAppointments.Any())
        {
            <table class="table table-striped">
                <thead><tr><th>Time</th><th>Pet</th><th>Reason</th><th>Vet</th></tr></thead>
                <tbody>
                    @foreach (var apt in upcomingAppointments)
                    {
                        <tr>
                            <td>@apt.StartTime.ToString("g")</td>
                            <td>@apt.Pet.Name</td>
                            <td>@apt.Reason</td>
                            <td>@apt.Veterinarian</td>
                        </tr>
                    }
                </tbody>
            </table>
        }
        else
        {
            <p class="text-muted">No upcoming appointments.</p>
        }
    </div>
    <div class="col-md-6">
        <h4>Recent Treatments</h4>
        @if (recentTreatments.Any())
        {
            <table class="table table-striped">
                <thead><tr><th>Date</th><th>Pet</th><th>Description</th></tr></thead>
                <tbody>
                    @foreach (var t in recentTreatments)
                    {
                        <tr>
                            <td>@t.Date.ToString("d")</td>
                            <td>@t.Pet.Name</td>
                            <td>@t.Description</td>
                        </tr>
                    }
                </tbody>
            </table>
        }
        else
        {
            <p class="text-muted">No recent treatments.</p>
        }
    </div>
</div>

@code {
    private int petCount;
    private int ownerCount;
    private int todayAppointments;
    private int unpaidInvoices;
    private List<Appointment> upcomingAppointments = new();
    private List<Treatment> recentTreatments = new();

    protected override async Task OnInitializedAsync()
    {
        petCount = await Db.Pets.CountAsync();
        ownerCount = await Db.Owners.CountAsync();
        todayAppointments = await Db.Appointments
            .Where(a => a.StartTime.Date == DateTime.Today && a.Status == AppointmentStatus.Scheduled)
            .CountAsync();
        unpaidInvoices = await Db.Invoices.Where(i => !i.IsPaid).CountAsync();

        upcomingAppointments = await Db.Appointments
            .Include(a => a.Pet)
            .Where(a => a.StartTime >= DateTime.Now && a.Status == AppointmentStatus.Scheduled)
            .OrderBy(a => a.StartTime)
            .Take(5)
            .ToListAsync();

        recentTreatments = await Db.Treatments
            .Include(t => t.Pet)
            .OrderByDescending(t => t.Date)
            .Take(5)
            .ToListAsync();
    }
}
```

