@page "/patients"
@using Microsoft.AspNetCore.Authorization
@using Microsoft.EntityFrameworkCore
@using VetClinic.Data
@attribute [Authorize]
@inject ApplicationDbContext Db

<PageTitle>Patients - VetClinic</PageTitle>

<h1>Patient Records</h1>

<div class="row mt-3">
    <div class="col-md-8">
        <div class="input-group mb-3">
            <input type="text" class="form-control" placeholder="Search pets or owners..."
                   @bind="searchTerm" @bind:event="oninput" />
            <button class="btn btn-outline-secondary" @onclick="Search">Search</button>
        </div>

        @if (showOwnerForm)
        {
            <div class="card mb-3">
                <div class="card-header">@(editingOwner.Id == 0 ? "New Owner" : "Edit Owner")</div>
                <div class="card-body">
                    <div class="row">
                        <div class="col-md-6 mb-2">
                            <label class="form-label">First Name</label>
                            <input class="form-control" @bind="editingOwner.FirstName" />
                        </div>
                        <div class="col-md-6 mb-2">
                            <label class="form-label">Last Name</label>
                            <input class="form-control" @bind="editingOwner.LastName" />
                        </div>
                        <div class="col-md-6 mb-2">
                            <label class="form-label">Phone</label>
                            <input class="form-control" @bind="editingOwner.Phone" />
                        </div>
                        <div class="col-md-6 mb-2">
                            <label class="form-label">Email</label>
                            <input class="form-control" @bind="editingOwner.Email" />
                        </div>
                    </div>
                    <button class="btn btn-primary me-2" @onclick="SaveOwner">Save Owner</button>
                    <button class="btn btn-secondary" @onclick="() => showOwnerForm = false">Cancel</button>
                </div>
            </div>
        }

        @if (showPetForm)
        {
            <div class="card mb-3">
                <div class="card-header">@(editingPet.Id == 0 ? "Register New Pet" : "Edit Pet")</div>
                <div class="card-body">
                    <div class="row">
                        <div class="col-md-6 mb-2">
                            <label class="form-label">Name</label>
                            <input class="form-control" @bind="editingPet.Name" />
                        </div>
                        <div class="col-md-6 mb-2">
                            <label class="form-label">Species</label>
                            <select class="form-select" @bind="editingPet.Species">
                                <option value="">Select...</option>
                                <option>Dog</option>
                                <option>Cat</option>
                                <option>Bird</option>
                                <option>Rabbit</option>
                                <option>Reptile</option>
                                <option>Other</option>
                            </select>
                        </div>
                        <div class="col-md-6 mb-2">
                            <label class="form-label">Breed</label>
                            <input class="form-control" @bind="editingPet.Breed" />
                        </div>
                        <div class="col-md-6 mb-2">
                            <label class="form-label">Date of Birth</label>
                            <input type="date" class="form-control" @bind="editingPet.DateOfBirth" />
                        </div>
                        <div class="col-md-6 mb-2">
                            <label class="form-label">Weight (kg)</label>
                            <input type="number" step="0.1" class="form-control" @bind="editingPet.Weight" />
                        </div>
                        <div class="col-md-6 mb-2">
                            <label class="form-label">Owner</label>
                            <select class="form-select" @bind="editingPet.OwnerId">
                                <option value="0">Select owner...</option>
                                @foreach (var owner in owners)
                                {
                                    <option value="@owner.Id">@owner.FirstName @owner.LastName</option>
                                }
                            </select>
                        </div>
                    </div>
                    <button class="btn btn-primary me-2" @onclick="SavePet">Save Pet</button>
                    <button class="btn btn-secondary" @onclick="() => showPetForm = false">Cancel</button>
                </div>
            </div>
        }

        <div class="mb-3">
            <button class="btn btn-success me-2" @onclick="NewOwner">+ New Owner</button>
            <button class="btn btn-success" @onclick="NewPet">+ Register Pet</button>
        </div>

        <table class="table table-hover">
            <thead><tr><th>Pet</th><th>Species</th><th>Breed</th><th>Owner</th><th>Actions</th></tr></thead>
            <tbody>
                @foreach (var pet in filteredPets)
                {
                    <tr @onclick="() => SelectPet(pet)" class="@(selectedPet?.Id == pet.Id ? "table-active" : "")" style="cursor:pointer">
                        <td>@pet.Name</td>
                        <td>@pet.Species</td>
                        <td>@pet.Breed</td>
                        <td>@pet.Owner.FirstName @pet.Owner.LastName</td>
                        <td>
                            <button class="btn btn-sm btn-outline-primary me-1" @onclick="() => EditPet(pet)" @onclick:stopPropagation="true">Edit</button>
                        </td>
                    </tr>
                }
            </tbody>
        </table>
    </div>

    <div class="col-md-4">
        @if (selectedPet != null)
        {
            <div class="card">
                <div class="card-header">
                    <h5>@selectedPet.Name — Medical History</h5>
                    <small class="text-muted">@selectedPet.Species · @selectedPet.Breed · @(((DateTime.Today - selectedPet.DateOfBirth).Days / 365.0).ToString("F1")) yrs</small>
                </div>
                <div class="card-body">
                    <h6>Treatments</h6>
                    @if (selectedPetTreatments.Any())
                    {
                        @foreach (var t in selectedPetTreatments)
                        {
                            <div class="border-bottom pb-2 mb-2">
                                <strong>@t.Date.ToString("d")</strong> — @t.Description<br />
                                <small class="text-muted">@t.Notes</small><br />
                                <small>Vet: @t.Veterinarian</small>
                            </div>
                        }
                    }
                    else
                    {
                        <p class="text-muted">No treatments recorded.</p>
                    }

                    <h6 class="mt-3">Add Treatment Note</h6>
                    <div class="mb-2">
                        <input class="form-control mb-1" placeholder="Description" @bind="newTreatment.Description" />
                        <textarea class="form-control mb-1" placeholder="Notes" @bind="newTreatment.Notes"></textarea>
                        <input class="form-control mb-1" placeholder="Veterinarian" @bind="newTreatment.Veterinarian" />
                        <button class="btn btn-sm btn-primary" @onclick="AddTreatment">Add Treatment</button>
                    </div>
                </div>
            </div>
        }
        else
        {
            <div class="alert alert-info">Select a pet to view medical history.</div>
        }
    </div>
</div>

@code {
    private List<Pet> pets = new();
    private List<Pet> filteredPets = new();
    private List<Owner> owners = new();
    private string searchTerm = "";
    private Pet? selectedPet;
    private List<Treatment> selectedPetTreatments = new();
    private Treatment newTreatment = new() { Date = DateTime.Today };

    private bool showOwnerForm;
    private bool showPetForm;
    private Owner editingOwner = new();
    private Pet editingPet = new() { DateOfBirth = DateTime.Today };

    protected override async Task OnInitializedAsync()
    {
        await LoadData();
    }

    private async Task LoadData()
    {
        pets = await Db.Pets.Include(p => p.Owner).OrderBy(p => p.Name).ToListAsync();
        owners = await Db.Owners.OrderBy(o => o.LastName).ToListAsync();
        Search();
    }

    private void Search()
    {
        if (string.IsNullOrWhiteSpace(searchTerm))
        {
            filteredPets = pets;
        }
        else
        {
            var term = searchTerm.ToLower();
            filteredPets = pets.Where(p =>
                p.Name.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                p.Owner.FirstName.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                p.Owner.LastName.Contains(term, StringComparison.OrdinalIgnoreCase)
            ).ToList();
        }
    }

    private async Task SelectPet(Pet pet)
    {
        selectedPet = pet;
        selectedPetTreatments = await Db.Treatments
            .Where(t => t.PetId == pet.Id)
            .OrderByDescending(t => t.Date)
            .ToListAsync();
        newTreatment = new Treatment { Date = DateTime.Today, PetId = pet.Id };
    }

    private void NewOwner()
    {
        editingOwner = new Owner();
        showOwnerForm = true;
    }

    private void NewPet()
    {
        editingPet = new Pet { DateOfBirth = DateTime.Today };
        showPetForm = true;
    }

    private void EditPet(Pet pet)
    {
        editingPet = pet;
        showPetForm = true;
    }

    private async Task SaveOwner()
    {
        if (editingOwner.Id == 0)
            Db.Owners.Add(editingOwner);
        await Db.SaveChangesAsync();
        showOwnerForm = false;
        await LoadData();
    }

    private async Task SavePet()
    {
        if (editingPet.Id == 0)
            Db.Pets.Add(editingPet);
        await Db.SaveChangesAsync();
        showPetForm = false;
        await LoadData();
    }

    private async Task AddTreatment()
    {
        if (selectedPet == null || string.IsNullOrWhiteSpace(newTreatment.Description)) return;
        newTreatment.PetId = selectedPet.Id;
        Db.Treatments.Add(newTreatment);
        await Db.SaveChangesAsync();
        await SelectPet(selectedPet);
    }
}

@page "/appointments"
@using Microsoft.AspNetCore.Authorization
@using Microsoft.EntityFrameworkCore
@using VetClinic.Data
@attribute [Authorize]
@inject ApplicationDbContext Db

<PageTitle>Appointments - VetClinic</PageTitle>

<h1>Appointment Scheduling</h1>

<div class="row mt-3">
    <div class="col-md-4">
        <div class="card">
            <div class="card-header">@(editingAppointment.Id == 0 ? "New Appointment" : "Edit Appointment")</div>
            <div class="card-body">
                <div class="mb-2">
                    <label class="form-label">Pet</label>
                    <select class="form-select" @bind="editingAppointment.PetId">
                        <option value="0">Select pet...</option>
                        @foreach (var pet in pets)
                        {
                            <option value="@pet.Id">@pet.Name (@pet.Owner.LastName)</option>
                        }
                    </select>
                </div>
                <div class="mb-2">
                    <label class="form-label">Date</label>
                    <input type="date" class="form-control" @bind="appointmentDate" @bind:event="onchange" @bind:after="CheckAvailability" />
                </div>
                <div class="mb-2">
                    <label class="form-label">Start Time</label>
                    <select class="form-select" @bind="selectedTimeSlot">
                        <option value="">Select time...</option>
                        @foreach (var slot in availableSlots)
                        {
                            <option value="@slot.ToString("HH:mm")">@slot.ToString("h:mm tt")</option>
                        }
                    </select>
                </div>
                <div class="mb-2">
                    <label class="form-label">Duration (minutes)</label>
                    <select class="form-select" @bind="durationMinutes">
                        <option value="15">15 min</option>
                        <option value="30">30 min</option>
                        <option value="45">45 min</option>
                        <option value="60">60 min</option>
                    </select>
                </div>
                <div class="mb-2">
                    <label class="form-label">Reason</label>
                    <input class="form-control" @bind="editingAppointment.Reason" />
                </div>
                <div class="mb-2">
                    <label class="form-label">Veterinarian</label>
                    <input class="form-control" @bind="editingAppointment.Veterinarian" />
                </div>
                <button class="btn btn-primary me-2" @onclick="SaveAppointment">Save</button>
                @if (editingAppointment.Id != 0)
                {
                    <button class="btn btn-secondary" @onclick="CancelEdit">Cancel</button>
                }
            </div>
        </div>
    </div>

    <div class="col-md-8">
        <div class="d-flex justify-content-between align-items-center mb-3">
            <button class="btn btn-outline-secondary" @onclick="PreviousWeek">← Previous</button>
            <h5>@weekStart.ToString("MMM d") — @weekStart.AddDays(6).ToString("MMM d, yyyy")</h5>
            <button class="btn btn-outline-secondary" @onclick="NextWeek">Next →</button>
        </div>

        <div class="table-responsive">
            <table class="table table-bordered">
                <thead>
                    <tr>
                        @for (int i = 0; i < 7; i++)
                        {
                            var day = weekStart.AddDays(i);
                            <th class="text-center @(day.Date == DateTime.Today ? "table-primary" : "")">
                                @day.ToString("ddd")<br />@day.ToString("M/d")
                            </th>
                        }
                    </tr>
                </thead>
                <tbody>
                    <tr>
                        @for (int i = 0; i < 7; i++)
                        {
                            var day = weekStart.AddDays(i);
                            var dayAppts = weekAppointments.Where(a => a.StartTime.Date == day.Date).OrderBy(a => a.StartTime).ToList();
                            <td style="vertical-align:top; min-width:120px;">
                                @foreach (var apt in dayAppts)
                                {
                                    <div class="p-1 mb-1 rounded small @GetStatusClass(apt.Status)" @onclick="() => EditAppointment(apt)" style="cursor:pointer">
                                        <strong>@apt.StartTime.ToString("h:mm tt")</strong><br />
                                        @apt.Pet.Name<br />
                                        <small>@apt.Reason</small>
                                    </div>
                                }
                            </td>
                        }
                    </tr>
                </tbody>
            </table>
        </div>

        <h5 class="mt-4">All Appointments</h5>
        <table class="table table-striped">
            <thead><tr><th>Date/Time</th><th>Pet</th><th>Reason</th><th>Vet</th><th>Status</th><th>Actions</th></tr></thead>
            <tbody>
                @foreach (var apt in weekAppointments.OrderBy(a => a.StartTime))
                {
                    <tr>
                        <td>@apt.StartTime.ToString("g")</td>
                        <td>@apt.Pet.Name</td>
                        <td>@apt.Reason</td>
                        <td>@apt.Veterinarian</td>
                        <td><span class="badge @GetBadgeClass(apt.Status)">@apt.Status</span></td>
                        <td>
                            @if (apt.Status == AppointmentStatus.Scheduled)
                            {
                                <button class="btn btn-sm btn-outline-primary me-1" @onclick="() => EditAppointment(apt)">Reschedule</button>
                                <button class="btn btn-sm btn-outline-danger" @onclick="() => CancelAppointment(apt)">Cancel</button>
                            }
                        </td>
                    </tr>
                }
            </tbody>
        </table>
    </div>
</div>

@code {
    private List<Pet> pets = new();
    private List<Appointment> weekAppointments = new();
    private Appointment editingAppointment = new();
    private DateTime weekStart;
    private DateOnly appointmentDate = DateOnly.FromDateTime(DateTime.Today);
    private string selectedTimeSlot = "";
    private int durationMinutes = 30;
    private List<DateTime> availableSlots = new();

    protected override async Task OnInitializedAsync()
    {
        weekStart = DateTime.Today.AddDays(-(int)DateTime.Today.DayOfWeek);
        pets = await Db.Pets.Include(p => p.Owner).OrderBy(p => p.Name).ToListAsync();
        await LoadWeekAppointments();
        await CheckAvailability();
    }

    private async Task LoadWeekAppointments()
    {
        var weekEnd = weekStart.AddDays(7);
        weekAppointments = await Db.Appointments
            .Include(a => a.Pet)
            .Where(a => a.StartTime >= weekStart && a.StartTime < weekEnd)
            .ToListAsync();
    }

    private async Task CheckAvailability()
    {
        var date = appointmentDate.ToDateTime(TimeOnly.MinValue);
        var dayAppointments = await Db.Appointments
            .Where(a => a.StartTime.Date == date.Date && a.Status != AppointmentStatus.Cancelled)
            .ToListAsync();

        availableSlots = new List<DateTime>();
        // Clinic hours: 8 AM to 6 PM, 30-minute slots
        for (var hour = 8; hour < 18; hour++)
        {
            for (var min = 0; min < 60; min += 30)
            {
                var slotTime = date.AddHours(hour).AddMinutes(min);
                var slotEnd = slotTime.AddMinutes(30);
                bool isAvailable = !dayAppointments.Any(a =>
                    a.StartTime < slotEnd && a.EndTime > slotTime);
                if (isAvailable)
                    availableSlots.Add(slotTime);
            }
        }
    }

    private async Task SaveAppointment()
    {
        if (editingAppointment.PetId == 0 || string.IsNullOrWhiteSpace(selectedTimeSlot)) return;

        var time = TimeOnly.Parse(selectedTimeSlot);
        editingAppointment.StartTime = appointmentDate.ToDateTime(time);
        editingAppointment.EndTime = editingAppointment.StartTime.AddMinutes(durationMinutes);
        editingAppointment.Status = AppointmentStatus.Scheduled;

        if (editingAppointment.Id == 0)
            Db.Appointments.Add(editingAppointment);

        await Db.SaveChangesAsync();
        editingAppointment = new Appointment();
        selectedTimeSlot = "";
        await LoadWeekAppointments();
        await CheckAvailability();
    }

    private void EditAppointment(Appointment apt)
    {
        editingAppointment = apt;
        appointmentDate = DateOnly.FromDateTime(apt.StartTime);
        selectedTimeSlot = apt.StartTime.ToString("HH:mm");
        durationMinutes = (int)(apt.EndTime - apt.StartTime).TotalMinutes;
    }

    private async Task CancelAppointment(Appointment apt)
    {
        apt.Status = AppointmentStatus.Cancelled;
        await Db.SaveChangesAsync();
        await LoadWeekAppointments();
    }

    private void CancelEdit()
    {
        editingAppointment = new Appointment();
        selectedTimeSlot = "";
    }

    private void PreviousWeek()
    {
        weekStart = weekStart.AddDays(-7);
        _ = LoadWeekAppointments();
    }

    private void NextWeek()
    {
        weekStart = weekStart.AddDays(7);
        _ = LoadWeekAppointments();
    }

    private string GetStatusClass(AppointmentStatus status) => status switch
    {
        AppointmentStatus.Scheduled => "bg-primary-subtle",
        AppointmentStatus.Completed => "bg-success-subtle",
        AppointmentStatus.Cancelled => "bg-danger-subtle",
        _ => ""
    };

    private string GetBadgeClass(AppointmentStatus status) => status switch
    {
        AppointmentStatus.Scheduled => "bg-primary",
        AppointmentStatus.Completed => "bg-success",
        AppointmentStatus.Cancelled => "bg-danger",
        _ => "bg-secondary"
    };
}

@page "/billing"
@using Microsoft.AspNetCore.Authorization
@using Microsoft.EntityFrameworkCore
@using VetClinic.Data
@attribute [Authorize]
@inject ApplicationDbContext Db

<PageTitle>Billing - VetClinic</PageTitle>

<h1>Billing &amp; Payments</h1>

<div class="row mt-3">
    <div class="col-md-5">
        <div class="card mb-3">
            <div class="card-header">@(editingInvoice.Id == 0 ? "Generate Invoice" : "Edit Invoice")</div>
            <div class="card-body">
                <div class="mb-2">
                    <label class="form-label">Pet</label>
                    <select class="form-select" @bind="editingInvoice.PetId">
                        <option value="0">Select pet...</option>
                        @foreach (var pet in pets)
                        {
                            <option value="@pet.Id">@pet.Name (@pet.Owner.LastName)</option>
                        }
                    </select>
                </div>
                <div class="mb-2">
                    <label class="form-label">Description</label>
                    <input class="form-control" @bind="editingInvoice.Description" />
                </div>

                <h6>Line Items</h6>
                @for (int i = 0; i < lineItems.Count; i++)
                {
                    var idx = i;
                    <div class="row mb-1">
                        <div class="col-5">
                            <input class="form-control form-control-sm" placeholder="Item" @bind="lineItems[idx].Description" />
                        </div>
                        <div class="col-2">
                            <input type="number" class="form-control form-control-sm" placeholder="Qty" @bind="lineItems[idx].Quantity" />
                        </div>
                        <div class="col-3">
                            <input type="number" step="0.01" class="form-control form-control-sm" placeholder="Amount" @bind="lineItems[idx].Amount" />
                        </div>
                        <div class="col-2">
                            <button class="btn btn-sm btn-outline-danger" @onclick="() => lineItems.RemoveAt(idx)">×</button>
                        </div>
                    </div>
                }
                <button class="btn btn-sm btn-outline-secondary mb-2" @onclick="() => lineItems.Add(new InvoiceLineItem { Quantity = 1 })">+ Add Item</button>

                <div class="mb-2">
                    <strong>Total: $@(lineItems.Sum(l => l.Amount * l.Quantity).ToString("F2"))</strong>
                </div>

                <button class="btn btn-primary me-2" @onclick="SaveInvoice">Save Invoice</button>
                @if (editingInvoice.Id != 0)
                {
                    <button class="btn btn-secondary" @onclick="CancelEdit">Cancel</button>
                }
            </div>
        </div>

        @if (selectedInvoice != null)
        {
            <div class="card">
                <div class="card-header">Process Payment — Invoice #@selectedInvoice.Id</div>
                <div class="card-body">
                    <p>Total: <strong>$@selectedInvoice.Total.ToString("F2")</strong> |
                       Paid: <strong>$@selectedInvoice.Payments.Sum(p => p.Amount).ToString("F2")</strong> |
                       Remaining: <strong>$@((selectedInvoice.Total - selectedInvoice.Payments.Sum(p => p.Amount)).ToString("F2"))</strong></p>
                    <div class="row">
                        <div class="col-md-6 mb-2">
                            <label class="form-label">Amount</label>
                            <input type="number" step="0.01" class="form-control" @bind="newPayment.Amount" />
                        </div>
                        <div class="col-md-6 mb-2">
                            <label class="form-label">Method</label>
                            <select class="form-select" @bind="newPayment.Method">
                                <option value="Cash">Cash</option>
                                <option value="Card">Card</option>
                                <option value="Check">Check</option>
                            </select>
                        </div>
                    </div>
                    <button class="btn btn-success" @onclick="ProcessPayment">Process Payment</button>

                    @if (selectedInvoice.Payments.Any())
                    {
                        <h6 class="mt-3">Payment History</h6>
                        <table class="table table-sm">
                            <thead><tr><th>Date</th><th>Amount</th><th>Method</th></tr></thead>
                            <tbody>
                                @foreach (var p in selectedInvoice.Payments)
                                {
                                    <tr><td>@p.Date.ToString("g")</td><td>$@p.Amount.ToString("F2")</td><td>@p.Method</td></tr>
                                }
                            </tbody>
                        </table>
                    }
                </div>
            </div>
        }
    </div>

    <div class="col-md-7">
        <ul class="nav nav-tabs mb-3">
            <li class="nav-item">
                <button class="nav-link @(showUnpaid ? "active" : "")" @onclick="() => showUnpaid = true">Unpaid</button>
            </li>
            <li class="nav-item">
                <button class="nav-link @(!showUnpaid ? "active" : "")" @onclick="() => showUnpaid = false">All Invoices</button>
            </li>
        </ul>

        <table class="table table-hover">
            <thead><tr><th>#</th><th>Date</th><th>Pet</th><th>Description</th><th>Total</th><th>Status</th><th>Actions</th></tr></thead>
            <tbody>
                @foreach (var inv in displayedInvoices)
                {
                    <tr class="@(selectedInvoice?.Id == inv.Id ? "table-active" : "")">
                        <td>@inv.Id</td>
                        <td>@inv.Date.ToString("d")</td>
                        <td>@inv.Pet.Name</td>
                        <td>@inv.Description</td>
                        <td>$@inv.Total.ToString("F2")</td>
                        <td>
                            @if (inv.IsPaid)
                            {
                                <span class="badge bg-success">Paid</span>
                            }
                            else
                            {
                                <span class="badge bg-warning">Unpaid</span>
                            }
                        </td>
                        <td>
                            <button class="btn btn-sm btn-outline-primary" @onclick="() => SelectInvoice(inv)">
                                @(inv.IsPaid ? "View" : "Pay")
                            </button>
                        </td>
                    </tr>
                }
            </tbody>
        </table>
    </div>
</div>

@code {
    private List<Pet> pets = new();
    private List<Invoice> invoices = new();
    private List<Invoice> displayedInvoices = new();
    private Invoice editingInvoice = new() { Date = DateTime.Today };
    private List<InvoiceLineItem> lineItems = new() { new InvoiceLineItem { Quantity = 1 } };
    private Invoice? selectedInvoice;
    private Payment newPayment = new() { Date = DateTime.Now, Method = "Cash" };
    private bool showUnpaid = true;

    protected override async Task OnInitializedAsync()
    {
        pets = await Db.Pets.Include(p => p.Owner).OrderBy(p => p.Name).ToListAsync();
        await LoadInvoices();
    }

    private async Task LoadInvoices()
    {
        invoices = await Db.Invoices
            .Include(i => i.Pet)
            .Include(i => i.Payments)
            .OrderByDescending(i => i.Date)
            .ToListAsync();
        FilterInvoices();
    }

    private void FilterInvoices()
    {
        displayedInvoices = showUnpaid
            ? invoices.Where(i => !i.IsPaid).ToList()
            : invoices;
    }

    private async Task SaveInvoice()
    {
        if (editingInvoice.PetId == 0) return;

        editingInvoice.Date = DateTime.Today;
        editingInvoice.Total = lineItems.Sum(l => l.Amount * l.Quantity);

        if (editingInvoice.Id == 0)
        {
            Db.Invoices.Add(editingInvoice);
            await Db.SaveChangesAsync();

            foreach (var item in lineItems)
            {
                item.InvoiceId = editingInvoice.Id;
                Db.InvoiceLineItems.Add(item);
            }
            await Db.SaveChangesAsync();
        }
        else
        {
            await Db.SaveChangesAsync();
        }

        editingInvoice = new Invoice { Date = DateTime.Today };
        lineItems = new List<InvoiceLineItem> { new InvoiceLineItem { Quantity = 1 } };
        await LoadInvoices();
    }

    private async Task SelectInvoice(Invoice inv)
    {
        selectedInvoice = await Db.Invoices
            .Include(i => i.Payments)
            .Include(i => i.Pet)
            .FirstOrDefaultAsync(i => i.Id == inv.Id);
        newPayment = new Payment { Date = DateTime.Now, Method = "Cash", Amount = (selectedInvoice!.Total - selectedInvoice.Payments.Sum(p => p.Amount)) };
    }

    private async Task ProcessPayment()
    {
        if (selectedInvoice == null || newPayment.Amount <= 0) return;

        newPayment.InvoiceId = selectedInvoice.Id;
        newPayment.Date = DateTime.Now;
        Db.Payments.Add(newPayment);

        var totalPaid = selectedInvoice.Payments.Sum(p => p.Amount) + newPayment.Amount;
        if (totalPaid >= selectedInvoice.Total)
            selectedInvoice.IsPaid = true;

        await Db.SaveChangesAsync();
        await SelectInvoice(selectedInvoice);
        await LoadInvoices();
    }

    private void CancelEdit()
    {
        editingInvoice = new Invoice { Date = DateTime.Today };
        lineItems = new List<InvoiceLineItem> { new InvoiceLineItem { Quantity = 1 } };
    }
}

